+.comment-form {
+  display: grid;
+  gap: 12px;
+  margin-top: 12px;
+}
+
+.comment-input {
+  border-radius: 16px;
+  border: 1px solid var(--line);
+  padding: 14px 16px;
+  font-size: 1rem;
+  background: var(--surface-muted);
+  color: var(--ink);
+  font-family: var(--font-body);
+  min-height: 120px;
+  resize: vertical;
+}
+
+.comment-input:focus-visible {
+  outline: 3px solid rgba(255, 107, 74, 0.25);
+  outline-offset: 3px;
+}
+
+.comment-submit {
+  justify-self: start;
+  padding: 8px 14px;
+  font-size: 0.9rem;
+}
+
